import React, { useState } from "react";
import { useAuth } from "../context/AuthContext";

export default function LoginPage({ onLogin }) {
  const { login, register } = useAuth();
  const [isRegister, setIsRegister] = useState(false);
  const [form, setForm] = useState({ username: "", email: "", password: "" });
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setLoading(true);
    try {
      if (isRegister) {
        await register(form.username, form.email, form.password);
      } else {
        await login(form.email, form.password);
      }
      onLogin && onLogin();
    } catch (err) {
      setError(err.response?.data?.message || "Something went wrong");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="h-screen w-screen flex overflow-hidden bg-background">
      {/* Left Panel */}
      <div className="hidden lg:flex w-1/2 bg-gradient-to-br from-primary to-primary-container flex-col items-center justify-center relative overflow-hidden">
        {/* Decorative circles */}
        <div className="absolute -top-20 -left-20 w-80 h-80 rounded-full bg-white/5"></div>
        <div className="absolute -bottom-32 -right-16 w-96 h-96 rounded-full bg-white/5"></div>
        <div className="absolute top-1/2 left-1/4 w-48 h-48 rounded-full bg-white/5"></div>

        <div className="float-anim text-center z-10 px-12">
          <div className="mb-8 flex justify-center">
            <div className="w-20 h-20 rounded-3xl bg-white/20 backdrop-blur flex items-center justify-center shadow-xl">
              <span className="text-white font-extrabold text-4xl">M</span>
            </div>
          </div>
          <h1 className="text-4xl font-extrabold text-white mb-4 leading-tight">
            Welcome to<br />chatVerse
          </h1>
          <p className="text-white/70 text-lg font-light max-w-sm">
            Connect, collaborate, and communicate in a weightless canvas designed for the future.
          </p>

          {/* Feature bullets */}
          <div className="mt-10 flex flex-col gap-3 text-left">
            {[
              { icon: "videocam", label: "HD Video & Voice Calls" },
              { icon: "mic", label: "AI Voice Messaging" },
              { icon: "share_screen", label: "Screen Sharing" },
              { icon: "attach_file", label: "Rich Media Sharing" },
            ].map((f) => (
              <div key={f.label} className="flex items-center gap-3 text-white/80">
                <div className="w-8 h-8 rounded-xl bg-white/20 flex items-center justify-center">
                  <span className="material-symbols-outlined text-sm text-white">{f.icon}</span>
                </div>
                <span className="text-sm font-medium">{f.label}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Right Panel - Form */}
      <div className="flex-1 flex items-center justify-center px-8">
        <div className="w-full max-w-md">
          {/* Logo for mobile */}
          <div className="lg:hidden flex justify-center mb-8">
            <div className="w-14 h-14 rounded-2xl bg-primary flex items-center justify-center shadow-lg shadow-primary/30">
              <span className="text-white font-extrabold text-2xl">M</span>
            </div>
          </div>

          <div className="mb-8">
            <h2 className="text-2xl font-bold text-on-surface mb-1">
              {isRegister ? "Create your account" : "Welcome back"}
            </h2>
            <p className="text-sm text-on-surface-variant">
              {isRegister
                ? "Join chatVerse today — it's free"
                : "Sign in to continue your conversations"}
            </p>
          </div>

          {error && (
            <div className="mb-4 px-4 py-3 bg-error-container text-on-error-container rounded-2xl text-sm font-medium">
              {error}
            </div>
          )}

          <form onSubmit={handleSubmit} className="flex flex-col gap-4">
            {isRegister && (
              <div>
                <label className="text-xs font-semibold text-on-surface-variant uppercase tracking-wider mb-1.5 block">
                  Username
                </label>
                <input
                  type="text"
                  placeholder="cooluser123"
                  value={form.username}
                  onChange={(e) => setForm({ ...form, username: e.target.value })}
                  className="w-full bg-surface-container-low border border-outline-variant rounded-2xl py-3 px-4 text-sm focus:ring-2 focus:ring-primary outline-none transition-all"
                  required
                />
              </div>
            )}
            <div>
              <label className="text-xs font-semibold text-on-surface-variant uppercase tracking-wider mb-1.5 block">
                Email
              </label>
              <input
                type="email"
                placeholder="you@email.com"
                value={form.email}
                onChange={(e) => setForm({ ...form, email: e.target.value })}
                className="w-full bg-surface-container-low border border-outline-variant rounded-2xl py-3 px-4 text-sm focus:ring-2 focus:ring-primary outline-none transition-all"
                required
              />
            </div>
            <div>
              <label className="text-xs font-semibold text-on-surface-variant uppercase tracking-wider mb-1.5 block">
                Password
              </label>
              <input
                type="password"
                placeholder="••••••••"
                value={form.password}
                onChange={(e) => setForm({ ...form, password: e.target.value })}
                className="w-full bg-surface-container-low border border-outline-variant rounded-2xl py-3 px-4 text-sm focus:ring-2 focus:ring-primary outline-none transition-all"
                required
                minLength={6}
              />
            </div>

            <button
              type="submit"
              disabled={loading}
              className="mt-2 w-full py-3.5 rounded-2xl bg-gradient-to-r from-primary to-primary-container text-white font-semibold text-sm shadow-lg shadow-primary/25 hover:shadow-xl hover:shadow-primary/35 hover:scale-[1.01] active:scale-[0.99] transition-all disabled:opacity-60 disabled:cursor-not-allowed"
            >
              {loading ? (
                <span className="flex items-center justify-center gap-2">
                  <svg className="animate-spin w-4 h-4" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"></path>
                  </svg>
                  {isRegister ? "Creating account..." : "Signing in..."}
                </span>
              ) : isRegister ? "Create Account" : "Sign In"}
            </button>
          </form>

          <p className="mt-6 text-center text-sm text-on-surface-variant">
            {isRegister ? "Already have an account?" : "Don't have an account?"}{" "}
            <button
              onClick={() => { setIsRegister(!isRegister); setError(""); }}
              className="text-primary font-semibold hover:underline"
            >
              {isRegister ? "Sign in" : "Create one"}
            </button>
          </p>
        </div>
      </div>
    </div>
  );
}
